#include <stdio.h>
#include <stdlib.h>
#include <omp.h>
#include <time.h>

#define ARRAY_SIZE 10000000

// Function to compute partial sum for a chunk
double partial_sum(double *arr, int start, int end) {
 double sum = 0.0;
 for (int i = start; i < end; i++) {
 sum += arr[i];
 }
 return sum;
}

int main() {
 double *array = malloc(ARRAY_SIZE * sizeof(double));

 // Initialize array with random values
 srand(time(NULL));
 for (int i = 0; i < ARRAY_SIZE; i++) {
 array[i] = (double)rand() / RAND_MAX;
 }

 // ============================================
 // SEQUENTIAL EXECUTION
 // ============================================
 double start_time = omp_get_wtime();
 double seq_sum = 0.0;
 for (int i = 0; i < ARRAY_SIZE; i++) {
 seq_sum += array[i];
 }
 double seq_time = omp_get_wtime() - start_time;
 printf("Sequential: Sum = %.2f, Time = %.4f seconds\n", seq_sum, seq_time);

 // ============================================
 // PARALLEL EXECUTION WITH OpenMP
 // ============================================
 int num_threads;
 #pragma omp parallel
 {
 #pragma omp master
 {
 num_threads = omp_get_num_threads();
 printf("OpenMP using %d threads\n", num_threads);
 }
 }

 double par_sum = 0.0;
 start_time = omp_get_wtime();

 // Parallel for loop - automatically distributes iterations
 #pragma omp parallel for reduction(+:par_sum)
 for (int i = 0; i < ARRAY_SIZE; i++) {
 par_sum += array[i];
 }

 double par_time = omp_get_wtime() - start_time;
 printf("Parallel: Sum = %.2f, Time = %.4f seconds\n", par_sum, par_time);
 printf("Speedup: %.2fx\n", seq_time / par_time);

 // ============================================
 // DEMONSTRATE SHARED VS PRIVATE VARIABLES
 // ============================================
 printf("\n--- Shared vs Private Demonstration ---\n");
 int shared_counter = 0;

 #pragma omp parallel for
 for (int i = 0; i < 10; i++) {
 int private_local = i; // Each thread has its own copy
 printf("Thread %d: i=%d, private_local=%d\n", 
 omp_get_thread_num(), i, private_local);
 #pragma omp atomic
 shared_counter++; // Requires synchronization for correct result
 }
 printf("Final shared_counter (should be 10): %d\n", shared_counter);

 free(array);
 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <mpi.h>
#include <time.h>

#define ARRAY_SIZE 10000000

int main(int argc, char *argv[]) {
 int rank, size;
 double *global_array = NULL;
 double *local_array;
 int local_size;
 double local_sum = 0.0, global_sum = 0.0;

 // Initialize MPI environment
 MPI_Init(&argc, &argv);
 MPI_Comm_rank(MPI_COMM_WORLD, &rank);
 MPI_Comm_size(MPI_COMM_WORLD, &size);

 if (rank == 0) {
 printf("=== MPI Parallel Array Sum ===\n");
 printf("Running on %d processes\n\n", size);
 }

 if (rank == 0) {
 // Master process: allocate and initialize data
 global_array = malloc(ARRAY_SIZE * sizeof(double));
 srand(time(NULL) + rank);
 for (int i = 0; i < ARRAY_SIZE; i++) {
 global_array[i] = (double)rand() / RAND_MAX;
 }
 }

 // ============================================
 // BROADCAST: Distribute array size to all processes
 // ============================================
 int n = ARRAY_SIZE;
 MPI_Bcast(&n, 1, MPI_INT, 0, MPI_COMM_WORLD);

 // Calculate local chunk size for each process
 local_size = n / size;
 local_array = malloc(local_size * sizeof(double));

 // ============================================
 // SCATTER: Distribute data chunks to all processes
 // ============================================
 double start_time = MPI_Wtime();

 MPI_Scatter(global_array, local_size, MPI_DOUBLE,
 local_array, local_size, MPI_DOUBLE,
 0, MPI_COMM_WORLD);

 // Each process computes local sum independently
 for (int i = 0; i < local_size; i++) {
 local_sum += local_array[i];
 }
 printf("Process %d: local_sum = %.2f (computed %d elements)\n", 
 rank, local_sum, local_size);

 // ============================================
 // REDUCE: Collect all local sums to root process
 // ============================================
 MPI_Reduce(&local_sum, &global_sum, 1, MPI_DOUBLE,
 MPI_SUM, 0, MPI_COMM_WORLD);

 double end_time = MPI_Wtime();

 if (rank == 0) {
 // Verify with sequential sum
 double seq_sum = 0.0;
 for (int i = 0; i < ARRAY_SIZE; i++) {
 seq_sum += global_array[i];
 }

 printf("\n=== Results ===\n");
 printf("Sequential sum: %.2f\n", seq_sum);
 printf("Parallel sum: %.2f\n", global_sum);
 printf("MPI_Wtime: %.4f seconds\n", end_time - start_time);

 free(global_array);
 }

 free(local_array);
 MPI_Finalize();
 return 0;
}

/* 
 Compile: mpicc -o mpi_sum mpi_sum.c -lm
 Run: mpirun -np 4 ./mpi_sum

 This demonstrates:
 - MPI_Scatter: Distributes data from root to all processes
 - MPI_Reduce: Aggregates results back to root (can also use MPI_Allreduce)
 - Each process operates on its own local memory (distributed memory model)
 - Explicit message passing replaces shared memory abstraction
*/
